const items = $input.all();
const branches = {};
let grandTotal = 0;
let needsManualCount = 0;

for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  if (row.status === 'Needs Manual') {
    needsManualCount++;
    continue;
  }
  if (row.status !== 'OK') continue;
  const branchName = row.branch || 'Unknown';
  const total = parseFloat(row.total) || 0;
  if (!branches[branchName]) branches[branchName] = { total: 0, creditors: [] };
  branches[branchName].total += total;
  branches[branchName].creditors.push({ supplier: row.supplier || 'Unknown', total: total });
  grandTotal += total;
}

const branchNames = Object.keys(branches);
const lines = [];
lines.push('\ud83e\uddfe *Outstanding \u2014 ' + DateTime.now().toFormat('yyyy-MM-dd') + '*');
lines.push('');
for (let i = 0; i < branchNames.length; i++) {
  const name = branchNames[i];
  const b = branches[name];
  b.creditors.sort(function (a, c) { return c.total - a.total; });
  const top5 = b.creditors.slice(0, 5);
  lines.push('*' + name + '* \u2014 R ' + b.total.toLocaleString('en-ZA'));
  for (let j = 0; j < top5.length; j++) {
    lines.push(' \u2022 ' + top5[j].supplier + ' \u2014 R ' + top5[j].total.toLocaleString('en-ZA'));
  }
  lines.push('');
}
lines.push('*Total owed:* R ' + grandTotal.toLocaleString('en-ZA'));
lines.push('\u26a0\ufe0f ' + needsManualCount + ' statements need manual entry');

return [{ json: { message: lines.join('\n') } }];
